package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testIsLineBreakWithNullCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreakWithLineFeedCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, Character.valueOf('\n'));
        assertTrue(result);
    }

    @Test
    void testIsLineBreakWithCarriageReturnCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, Character.valueOf('\r'));
        assertTrue(result);
    }

    @Test
    void testIsLineBreakWithNonLineBreakCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, Character.valueOf('a'));
        assertFalse(result);
    }

    @Test
    void testIsLineBreakCharLF() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (int) '\n');
        assertTrue(result);
    }

    @Test
    void testIsLineBreakCharCR() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (int) '\r');
        assertTrue(result);
    }

    @Test
    void testIsLineBreakCharOther() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (int) 'x');
        assertFalse(result);
    }
}
